function q(pregunta, opciones, correcta, explicacion) {
  return { pregunta, opciones, correcta, explicacion_profunda: explicacion, concepto_reforzado: pregunta.split(':')[0] };
}

function leccion(id, bloque, titulo, explicacion, analogia, ejemplo_malo, ejemplo_bueno, por_que_importa, tip_profesional, verificacion, practicaData, siguiente_concepto, por_que_importa_despues) {
  const [tipo, contexto, instruccion, input_malo, pista, solucion, criterios] = practicaData
    ? [practicaData.tipo, practicaData.contexto, practicaData.instruccion, practicaData.input_malo, practicaData.pista, practicaData.solucion, practicaData.criterios]
    : ["reescribir", "", "", "", "", "", []];
  return {
    id, titulo, bloque, tipo: "leccion", duracion_min: 20, xp: 50,
    contenido: {
      teoria: { explicacion, analogia, ejemplo_malo, ejemplo_bueno, por_que_importa, tip_profesional },
      verificacion,
      practica: { tipo, contexto, instruccion, input_malo, pista, solucion, criterios_de_exito: criterios },
      conexion: { siguiente_concepto, por_que_importa_despues }
    }
  };
}

